module divide_by_8 (  
    input wire [2:0] in,  
    output reg [2:0] out,  
    input wire clk,  
    input wire rst  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
        if (rst)  
            out <= 3'b000;  
        else  
            out <= in >> 3;  
    end  
endmodule
